<?php
require_once __DIR__.'/../../config/auth.php';require_once __DIR__.'/../../config/database.php';require_once __DIR__.'/../../config/helper.php';require_admin();
$pdo=db();$id=max(0,(int)($_GET['id']??$_POST['id']??0));if(!$pdo||!$id){flash('error','Pengguna tidak ditemukan.');redirect('admin/user/index.php');}$s=$pdo->prepare('SELECT id,nama,username FROM users WHERE id=?');$s->execute([$id]);$row=$s->fetch();if(!$row){flash('error','Pengguna tidak ditemukan.');redirect('admin/user/index.php');}$errors=[];
if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf();$p=(string)($_POST['password']??'');$c=(string)($_POST['password_confirmation']??'');if(strlen($p)<8)$errors[]='Password minimal 8 karakter.';if($p!==$c)$errors[]='Konfirmasi password tidak sama.';if(!$errors){$u=$pdo->prepare('UPDATE users SET password=? WHERE id=?');$u->execute([password_hash($p,PASSWORD_DEFAULT),$id]);log_activity($pdo,(int)current_user()['id'],'Mereset password @'.$row['username']);flash('success','Password '.$row['nama'].' berhasil diubah.');redirect('admin/user/index.php');}}
$adminPageTitle='Reset Password';$adminPageDescription='Tetapkan password baru untuk akun pengguna.';$adminActive='user';include __DIR__.'/../../includes/admin_header.php';
